class Solution {
public:
    string discountPrices(string sentence, int discount) {
        istringstream iss(sentence);
        string word;
        string result;
        while (iss >> word) {
            if (word.size() > 1 && word[0] == '$' && all_of(word.begin() + 1, word.end(), ::isdigit)) {
                long long price = stoll(word.substr(1));
                double discountedPrice = price * (100 - discount) / 100.0;
                char buffer[20];
                sprintf(buffer, "$%.2f", discountedPrice);
                result += buffer;
            } else {
                result += word;
            }
            result += ' ';
        }
        if (!result.empty()) result.pop_back();
        return result;
    }
};
